.darma-loader-darma-custom-513 {color: var(--loader-color, #2563eb);
   width: 32px;
   height: 16px;
   display: flex;
   animation: darma-loader-darma-custom-513-l9-0 1s infinite;
}
.darma-loader-darma-custom-513:before, .darma-loader-darma-custom-513:after  {
  content: "";
   flex: 1;
   background: var(--loader-color, #2563eb);
   transform-origin: top right;
   animation: darma-loader-darma-custom-513-l9-1 1s infinite;
}
.darma-loader-darma-custom-513:after  {
  background: var(--loader-secondary-color, #38bdf8);
   transform-origin: top left;
   --s:-1;
}
@keyframes darma-loader-darma-custom-513-l9-0  {
  100% {transform: translateY(100%)}
}
@keyframes darma-loader-darma-custom-513-l9-1  {
  100% {transform: rotate(calc(var(--s,1)*90deg))}
}

